--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelExplore:OnModelInit()
    self:ParseConfig()

    self:ModelNetMsgRecv(LProtoIds.ExploreMessageResp,function (...) self:OnExploreMessageResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.CreateExploreResp,function (...) self:OnCreateExploreResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.FlushExploreMissionResp,function (...) self:OnFlushExploreMissionResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ReceiveExploreTaskResp,function (...) self:OnReceiveExploreTaskResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.SettingTaskQualityResp,function (...) self:OnSettingTaskQualityResp(...) end)
    --self:ModelNetMsgRecv(LProtoIds.ExplorePrivilegeBuyResp,function (...) self:OnExplorePrivilegeBuyResp(...) end)
end


--在协议数据处理完之后需要调用finish
function ModelExplore:OnModelRequest()
    self:ModelFinish()
end


-------------------------------------------------
---req
function ModelExplore:ExploreMessageReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.ExploreMessageReq)
    SendMessage(pb,LProtoIds.ExploreMessageReq)
end

function ModelExplore:CreateExploreReq(missionId,heroList,exploreType)
    local pb = LProtoHelper.CreateProto(LProtoIds.CreateExploreReq)
    pb.type = exploreType or 0
    pb.missionIds = missionId
    local heroIds = pb.heroIds
    if not table.isempty(heroList) then
        for k,v in ipairs(heroList) do
            heroIds:append(v)
        end
    end

    SendMessage(pb,LProtoIds.CreateExploreReq)
end

function ModelExplore:ReceiveExploreTaskReq(type,missionId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ReceiveExploreTaskReq)
    pb.type = type
    if type == 1 then
        pb.missionId =missionId
    end
    SendMessage(pb,LProtoIds.ReceiveExploreTaskReq)
end
function ModelExplore:FlushExploreMissionReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.FlushExploreMissionReq)

    SendMessage(pb,LProtoIds.FlushExploreMissionReq)

    self:AddReqProtect()
end

function ModelExplore:ExplorePrivilegeBuyReq(type)
    local pb = LProtoHelper.CreateProto(LProtoIds.ExplorePrivilegeBuyReq)
    pb.type= type
    SendMessage(pb,LProtoIds.ExplorePrivilegeBuyReq)
end

function ModelExplore:SettingTaskQualityReq(type, qualityList)
    local pb = LProtoHelper.CreateProto(LProtoIds.SettingTaskQualityReq)
    pb.type= type or 0

    local quality = pb.quality
    if not table.isempty(qualityList) then
        for k,v in ipairs(qualityList) do
            quality:append(v)
        end
    end

    SendMessage(pb,LProtoIds.SettingTaskQualityReq)
end

