---resp
function ModelExplore:OnExploreMessageResp(pb)
    self._exploreList ={}
    for k,v in ipairs(pb.missionIds) do
        local explore =StructExplore:New()
        explore:CreateByRefId(v)
        table.insert(self._exploreList,explore)
    end

    for k,v in ipairs(pb.executeMissionList) do
        local explore = StructExplore:New()
        explore:CreateByPb(v)
        table.insert(self._exploreList,explore)
    end

    self._excutedHeros={}
    for k,v in ipairs(pb.executeHeroIds) do
        self._excutedHeros[v] = true
    end
    --self._lowPrivilegeTime = pb.lowPrivilegeTime
    --self._highPrivilegeTime = pb.highPrivilegeTime
    self._flushCount = pb.flushCount
    self._freeFlushCount = pb.freeFlushCount

    self:SortExploreList()
end

function ModelExplore:OnCreateExploreResp(pb)
    local exploreList = pb.explore
    local explore = exploreList[1]
    local cnt = #self._exploreList
    local index = nil

    for i=1,cnt do
        local data = self._exploreList[i]
        local state = data:GetState()
        if state== StructExplore.UNSTART and data:GetRefId() == explore.refId then
            data:CreateByPb(explore)
            index = i
            break
        end
    end

    local heroIds = explore.heroIds
    if not table.isempty(heroIds) then
        for k,v in ipairs(explore.heroIds) do
            self._excutedHeros[v] = true
        end
    end

    FireEvent(EventNames.ON_CREATE_EXPLORE,index)
end

function ModelExplore:OnFlushExploreMissionResp(pb)

    local cnt = #self._exploreList
    for i=cnt,1,-1 do
        local data = self._exploreList[i]
        local state = data:GetState()
        if state== StructExplore.UNSTART then
            table.remove(self._exploreList,i)
        end
    end

    for k,v in ipairs(pb.missionIds) do
        local explore =StructExplore:New()
        explore:CreateByRefId(v)
        table.insert(self._exploreList,explore)
    end

    self._flushCount = self._flushCount+1

    self:SortExploreList()

    self:ReleaseReqProtect()
end

function ModelExplore:OnReceiveExploreTaskResp(pb)
    local received = {}
    for k,v in ipairs(pb.receiveList) do
        received[v] = true
    end

    local indexList = {}

    local cnt = #self._exploreList
    for i=cnt,1,-1 do
        local data = self._exploreList[i]
        local id = data:GetId()
        if id and received[id] then

            table.insert(indexList,i)
            table.remove(self._exploreList,i)
            local heroIds = data:GetHeroIds()
            for k,v in ipairs(heroIds) do
                self._excutedHeros[v] = false
            end
        end

    end
    table.sort(indexList,function (a,b)
        return a>b
    end)

    FireEvent(EventNames.ON_RECEIVE_EXPLORE_REWARD,indexList,received)

    --FireEvent(EventNames.EXPLORE_RED_POINT)
end

function ModelExplore:OnSettingTaskQualityResp(pb)
    local type = pb.type
    local quality = pb.quality

    self._settingTaskQuality = {}
    for k,v in ipairs(quality) do
        self._settingTaskQuality[v] = true
    end
end

