function ModelExplore:SortExploreList()
    local list = self._exploreList
    local comp = function(a,b )
        local aState = a:GetState()
        local bState = b:GetState()
        if aState~= bState then
            return aState<bState
        else
            return a:GetQuality()>b:GetQuality()
        end
    end

    table.sort(list,comp)
end

function ModelExplore:GetExploreList()
    return self._exploreList
end

function ModelExplore:GetQuickCost(timeLeft)
    local refId = 1
    for k,v in ipairs(GameTable.InvestigateQuickCostRef) do
        local min = v.min
        local max = v.max
        if timeLeft>=min and timeLeft<= max then
            refId= k
            break
        end
    end

    return self._quickCostExpend[refId]
end

