function ModelExplore:GetExploreCondition(refId)
    local conditionList = self._exploreCondition[refId]
    local t ={}
    for k,v in ipairs(conditionList) do
        local condition = self._conditions[v]
        table.insert(t,condition)
    end
    return t
end

