function ModelExplore:ParseConfig()
    self._quickCostExpend ={}
    for k,v in ipairs(GameTable.InvestigateQuickCostRef) do
        local expend = v.expend
        self._quickCostExpend[k] = LxDataHelper.ParseItem_3(expend)
    end

    self._exploreReward={}
    self._exploreExpend ={}
    self._exploreCondition={}
    for k,v in pairs(GameTable.InvestigateTaskMainRef) do
        local reward = v.reward
        self._exploreReward[k] = LxDataHelper.ParseItem(reward)
        local condition = v.condition
        self._exploreCondition[k] = self:ParseExploreCondition(condition)
        local expend = v.expend
        self._exploreExpend[k] = LxDataHelper.ParseItem_3(expend)
    end

    self._refreshCost = LxDataHelper.ParseItem_3(GameTable.InvestigateConfigRef["refreshCost"])
    self._refreshCost2 = LxDataHelper.ParseItem_3(GameTable.InvestigateConfigRef["refreshCost2"])

    self._conditions ={}
    for k,v in pairs(GameTable.InvestigateConditionRef) do
        local condition = v.condition
        self._conditions[k] = self:ParseCondition(condition)
    end
end

function ModelExplore:ParseExploreCondition(str)
    local t = {}
    local temp = string.split(str,';')
    for k,v in ipairs(temp) do
        table.insert(t,tonumber(v))
    end
    return t
end

function ModelExplore:ParseCondition(str)
    local s,e,cap1,cap2,cap3 = string.find(str,"(%d+)=(%w+)=(%d+)")
    if not cap1 or not cap2 or not cap3 then
        printErrorN("ModelExplore:ParseCondition, wrong cfg "..str)
        return
    end
    local data =
    {
         itemNum = tonumber(cap1),
         type = cap2,
         typePara = tonumber(cap3)
    }
    return data
end

function ModelExplore:AddReqProtect()
    self._reqTime = GetTimestamp()
end

function ModelExplore:ReleaseReqProtect()
    self._reqTime = nil
end

function ModelExplore:IsProtect()
    if not self._reqTime then
        return false
    end
    local timeLast = GetTimestamp() - self._reqTime
    if timeLast > 1 then
        return false
    end

    return true
end

function ModelExplore:GetConditionRef(refId)
    local ref =  GameTable.InvestigateConditionRef[refId]
    return ref
end


function ModelExplore:CheckCanReceive(refId)
    local cfg = self:GetExploreConfig(refId)
    local condition =LxDataHelper.ParseNumber_Sign(cfg.condition,';')

    local starNum= 0
    local raceList = {}
    local starCondition = nil
    for k,v in ipairs(condition) do
        local ref = self:GetConditionRef(v)
        local para = self:ParseCondition(ref.condition)
        if para.type == ModelExplore.CONDITION_TYPE_STAR then
            starNum = para.typePara
            starCondition = v
        elseif para.type == ModelExplore.CONDITION_TYPE_RACE then
            local race = para.typePara

            local data =
            {
                refId = v,
                race = race,
                isEmpty = true,
                cnt = para.itemNum,
            }

            table.insert(raceList,data)
        end
    end

    local filter = {}
    local filterCnt = {}
    local total = 0
    for k,v in pairs(raceList) do
        local race = v.race
        filter[race] = true
        if not filterCnt[race] then
            filterCnt[race] = 1
        else
            filterCnt[race] = filterCnt[race]+ 1
        end
        total = total +1
    end

    local heroList = gModelHero:GetHeroList()
    local filteredList = {}
    for k,v in pairs(filter) do
        filteredList[k] = {}
    end

    local otherRaceList ={}
    for k,v in pairs(heroList) do
        local heroId = v:GetId()
        local star = v:GetStar()
        local race = gModelHero:GetTypeById(heroId)
        local isExecuted = self:IsHeroExecuted(heroId)
        if not isExecuted then
            if filter[race] then
                local raceHeroList = filteredList[race]
                table.insert(raceHeroList,v)
            else
                if star>= starNum then
                    table.insert(otherRaceList,v)
                end
            end
        end
    end

    local receiveList ={}
    local isFind = false
    for k,v in pairs(filter) do
        local raceHeroList = filteredList[k]
        if #raceHeroList>0 then
            table.sort(raceHeroList,function (a,b) return
            a:GetStar()<b:GetStar()
            end)
        end
        local cnt = filterCnt[k]
        local isSearched = false
        for i=1,cnt do
            local herodata =nil
            if #raceHeroList <=0 then
                break
            end
            if not isFind and not isSearched then

                local totalNum = #raceHeroList
                for j=1,totalNum do
                    local data = raceHeroList[j]
                    if data:GetStar()>= starNum then
                        isFind = true
                        herodata = table.remove(raceHeroList,j)
                        break
                    end
                end
                isSearched = true
                if not isFind then
                    herodata = table.remove(raceHeroList,1)
                end
            else
                herodata = table.remove(raceHeroList,1)
            end
            table.insert(receiveList,herodata)
        end
    end

    local isSuc = false
    if  #receiveList == total then
        if isFind then
            isSuc = true
        else
            if #otherRaceList > 0 then
                isSuc = true
            end
        end
    end


    return isSuc
end

function ModelExplore:GetReceiveQualityList()
    if self._settingTaskQuality then
        return table.clone(self._settingTaskQuality)
    end

    local defaultquality = GameTable.InvestigateConfigRef["defaultquality"]
    local defaultqualityList = string.split(defaultquality, ',')
    local result = {}
    for k,v in ipairs(defaultqualityList) do
        local typeIndex = tonumber(v)
        result[typeIndex] = true
    end
    return result
end
